package structs

import (
	"reflect"
	"slices"
	"time"
)

const VolumeTypeSandbox = "sandbox"

type SandboxVolume struct {
	// ID is a UUID-like string generated by the server.
	ID string

	// Namespace is the Nomad namespace for the host volume, which constrains
	// which jobs can mount it.
	Namespace string

	// Name is the name that group.volume will use to identify the volume
	// source. Not expected to be unique.
	Name string

	// AllocIDs are the allocations that claim this sandbox. May be empty if no
	// allocation currently claims the sandbox.
	AllocIDs []string

	// NodeID is the node where the volume is placed.
	NodeID string

	// Size of the sandbox in bytes
	CapacityBytes int64

	MaxClaims int

	// TTL is the lifetime remaining of the sandbox. Set when unclaimed and
	// reset to 0 (ignored) when claimed. Once this TTL expires, the sandbox is
	// eligible for garbage collection.
	TTL time.Duration

	CreateIndex uint64
	CreateTime  int64 // Unix timestamp in nanoseconds since epoch

	ModifyIndex uint64
	ModifyTime  int64 // Unix timestamp in nanoseconds since epoch
}

func (v *SandboxVolume) Copy() *SandboxVolume {
	if v == nil {
		return nil
	}

	nv := *v
	return &nv
}

func (v *SandboxVolume) IsFree(forMode VolumeAccessMode) bool {
	switch forMode {
	case HostVolumeAccessModeSingleNodeSingleWriter:
		return len(v.AllocIDs) == 0
	default:
		// TODO: check r/o?
	}
	return true
}

type AllocatedSandboxes []*AllocatedSandbox

func (as AllocatedSandboxes) Copy() AllocatedSandboxes {
	if len(as) == 0 {
		return nil
	}

	return slices.Clone(as) // AllocatedSandbox is all primitives
}

// AllocatedSandbox is the minimum data that a plan needs to add to
// AllocatedResources for us to claim/unclaim or upsert a SandboxVolume for an
// Allocation that's added or removed in the plan.
type AllocatedSandbox struct {
	ID            string
	Namespace     string
	Name          string
	CapacityBytes int64
	TTL           time.Duration
}

func (as *AllocatedSandbox) Equal(o *AllocatedSandbox) bool {
	if as == nil && o == nil {
		return true
	}
	if (as != nil && o == nil) || (as == nil && o != nil) {
		return false
	}
	// TODO: come back and do this without reflection
	return reflect.DeepEqual(as, o)
}

// SandboxVolumeRequest is the object that the job authors uses to configure a
// sandbox, found in the jobspec under job.group.volume.sandbox
type SandboxVolumeRequest struct {
	// MaxCount in the maximum number of identical sandboxes with this name and
	// namespace that should be created. We'll always try to reclaim oldest
	// sandboxes first.
	MaxCount int

	// MaxClaims is the maximum number of allocations that can claim a given
	// sandbox instance
	MaxClaims int

	// TTL is the lifetime of an unclaimed sandbox. After this point it can be
	// garbage collected.
	TTL time.Duration

	MinBytes int64
	MaxBytes int64
}

func (svr *SandboxVolumeRequest) Equal(o *SandboxVolumeRequest) bool {
	if svr == nil && o == nil {
		return true
	}
	if (svr != nil && o == nil) || (svr == nil && o != nil) {
		return false
	}
	switch {
	case svr.MaxCount != o.MaxCount:
		return false
	case svr.MaxClaims != o.MaxClaims:
		return false
	case svr.MaxBytes != o.MaxBytes:
		return false
	case svr.MinBytes != o.MinBytes:
		return false
	}
	return true
}

func (svr *SandboxVolumeRequest) Copy() *SandboxVolumeRequest {
	if svr == nil {
		return nil
	}
	nsvr := new(SandboxVolumeRequest)
	*nsvr = *svr
	return nsvr
}
